 15→// Lexical format flags
 16→const FORMAT_BOLD = 1;
 17→const FORMAT_ITALIC = 2;
 18→const FORMAT_UNDERLINE = 8;
 19→const FORMAT_STRIKETHROUGH = 4;
 20→
 21→interface LexicalNode {
 22→  type?: string;
 23→  tag?: string;
 24→  text?: string;
 25→  format?: number;
 26→  children?: LexicalNode[];
 27→  src?: string;
 28→  altText?: string;
 29→  width?: number;
 30→  height?: number;
 31→  url?: string;
 32→  direction?: string | null;
 33→}
 34→
 35→interface LexicalRendererProps {
 36→  content: string | object | null | undefined;
 37→  maxImages?: number;
 38→}
 39→
 40→function parseContent(raw: string | object | null | undefined): LexicalNode | null {
 41→  if (!raw) return null;
 42→  try {
 43→    const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
 44→    return parsed?.root ?? parsed;
 45→  } catch {
 46→    return null;
 47→  }
 48→}
 49→
 50→function TextSpan({node, colors}: {node: LexicalNode; colors: Palette}) {
 51→  if (node.type === 'linebreak') {
 52→    return <Text>{'\n'}</Text>;
 53→  }
 54→
 55→  if (node.type !== 'text' || !node.text) return null;
 56→
 57→  const fmt = node.format ?? 0;
 58→  const style: any = {
 59→    color: colors.textPrimary,
 60→    fontFamily: fonts.serif.regular,
 61→    fontSize: 16,
 62→    lineHeight: 26,
 63→  };
 64→
 65→  if (fmt & FORMAT_BOLD) {
 66→    style.fontFamily = fonts.serif.bold;
 67→    style.fontWeight = '700';
 68→  }
 69→  if (fmt & FORMAT_ITALIC) {
 70→    style.fontFamily = fonts.serif.italic;
 71→    style.fontStyle = 'italic';
 72→  }
 73→  if (fmt & FORMAT_UNDERLINE) {
 74→    style.textDecorationLine = 'underline';
 75→  }
 76→  if (fmt & FORMAT_STRIKETHROUGH) {
 77→    style.textDecorationLine = style.textDecorationLine
 78→      ? 'underline line-through'
 79→      : 'line-through';
 80→  }
 81→
 82→  return <Text style={style}>{node.text}</Text>;
 83→}
 84→
 85→function RenderNode({node, colors}: {node: LexicalNode; colors: Palette}) {
 86→  if (!node || !node.type) return null;
 87→
 88→  switch (node.type) {
 89→    case 'paragraph': {
 90→      if (!node.children || node.children.length === 0) {
 91→        return <View style={styles.paragraphGap} />;
 92→      }
 93→      return (
 94→        <Text style={[styles.paragraph, {color: colors.textPrimary}]}>
 95→          {node.children.map((child, i) => (
 96→            <RenderInline key={i} node={child} colors={colors} />
 97→          ))}
 98→        </Text>
 99→      );
100→    }
101→
102→    case 'heading': {
103→      const headingStyle =
104→        node.tag === 'h1'
105→          ? styles.h1
106→          : node.tag === 'h2'
107→            ? styles.h2
108→            : styles.h3;
109→      return (
110→        <Text style={[headingStyle, {color: colors.textHeading}]}>
111→          {node.children?.map((child, i) => (
112→            <RenderInline key={i} node={child} colors={colors} />
113→          ))}
114→        </Text>
115→      );
116→    }
117→
118→    case 'quote': {
119→      return (
120→        <View
121→          style={[
122→            styles.blockquote,
123→            {borderLeftColor: colors.accentAmber},
124→          ]}>
125→          <Text style={[styles.quoteText, {color: colors.textSecondary}]}>
126→            {node.children?.map((child, i) => (
127→              <RenderInline key={i} node={child} colors={colors} />
128→            ))}
129→          </Text>
130→        </View>
131→      );
132→    }
133→
134→    case 'image': {
135→      if (!node.src) return null;
136→      return (
137→        <View style={styles.imageWrapper}>
138→          <Image
139→            source={{uri: node.src}}
140→            style={styles.image}
141→            resizeMode="contain"
142→            accessibilityLabel={node.altText}
143→          />
144→        </View>
145→      );
146→    }
147→
148→    case 'link': {
149→      return (
150→        <Pressable
151→          onPress={() => node.url && Linking.openURL(node.url)}>
152→          <Text style={[styles.link, {color: colors.accentAmber}]}>
153→            {node.children?.map((child, i) => (
154→              <RenderInline key={i} node={child} colors={colors} />
155→            ))}
156→          </Text>
157→        </Pressable>
158→      );
159→    }
160→
161→    case 'list': {
162→      return (
163→        <View style={styles.list}>
164→          {node.children?.map((child, i) => (
165→            <RenderNode key={i} node={child} colors={colors} />
166→          ))}
167→        </View>
168→      );
169→    }
170→
171→    case 'listitem': {
172→      return (
173→        <View style={styles.listItem}>
174→          <Text style={[styles.listBullet, {color: colors.textMuted}]}>
175→            {'\u2022'}
176→          </Text>
177→          <Text style={[styles.paragraph, {color: colors.textPrimary, flex: 1}]}>
178→            {node.children?.map((child, i) => (
179→              <RenderInline key={i} node={child} colors={colors} />
180→            ))}
181→          </Text>
182→        </View>
183→      );
184→    }
185→
186→    default: {
187→      // Recurse into unknown container nodes
188→      if (node.children) {
189→        return (
190→          <View>
191→            {node.children.map((child, i) => (
192→              <RenderNode key={i} node={child} colors={colors} />
193→            ))}
194→          </View>
195→        );
196→      }
197→      return null;
198→    }
199→  }
200→}
201→
202→function RenderInline({node, colors}: {node: LexicalNode; colors: Palette}) {
203→  if (!node) return null;
204→  if (node.type === 'text' || node.type === 'linebreak') {
205→    return <TextSpan node={node} colors={colors} />;
206→  }
207→  if (node.type === 'link') {
208→    return (
209→      <Text
210→        style={{color: colors.accentAmber, textDecorationLine: 'underline'}}
211→        onPress={() => node.url && Linking.openURL(node.url)}>
212→        {node.children?.map((child, i) => (
213→          <RenderInline key={i} node={child} colors={colors} />
214→        ))}
215→      </Text>
216→    );
217→  }
218→  // Fallback: render children as inline
219→  if (node.children) {
220→    return (
221→      <>
222→        {node.children.map((child, i) => (
223→          <RenderInline key={i} node={child} colors={colors} />
224→        ))}
225→      </>
226→    );
227→  }
228→  return null;
229→}
230→
231→export function LexicalRenderer({content}: LexicalRendererProps) {
232→  const {colors} = useTheme();
233→  const root = parseContent(content);
234→
235→  if (!root || !root.children || root.children.length === 0) {
236→    return (
237→      <Text style={[styles.paragraph, {color: colors.textMuted}]}>
238→        No content available.
239→      </Text>
240→    );
241→  }
242→
243→  return (
244→    <View style={styles.container}>
245→      {root.children.map((node, i) => (
246→        <RenderNode key={i} node={node} colors={colors} />
247→      ))}
248→    </View>
249→  );
250→}
