 7→export const stripHtml = (html: string): string => {
 8→  return html
 9→    .replace(/<[^>]*>/g, ' ')
10→    .replace(/&nbsp;/g, ' ')
11→    .replace(/\s+/g, ' ')
12→    .trim();
13→};
