15→export const toLexicalFromPlainText = (plainText: string): string => {
16→  const payload = {
17→    root: {
18→      children: [
19→        {
20→          type: 'paragraph',
21→          children: [
22→            {
23→              type: 'text',
24→              text: plainText,
25→              detail: 0,
26→              format: 0,
27→              mode: 'normal',
28→              style: '',
29→              version: 1,
30→            },
31→          ],
32→          direction: null,
33→          format: '',
34→          indent: 0,
35→          version: 1,
36→        },
37→      ],
38→      direction: null,
39→      format: '',
40→      indent: 0,
41→      type: 'root',
42→      version: 1,
43→    },
44→  };
45→
46→  return JSON.stringify(payload);
47→};
